Se crea un metodo auxiliar que asigna prioridad numerica a cada posicion:

private int prioridadPosicion(Posicion p) {
    return switch(p) {
        case PORTERO -> 1;
        case DEFENSA -> 2;
        case CENTROCAMPISTA -> 3;
        case DELANTERO -> 4;
    };
}

